solution: ```class Solution {
    public int[] earliestAndLatest(int n, int firstPlayer, int secondPlayer) {
        return dfs(n, firstPlayer, secondPlayer, new int[29][29][29]);
    }

    private int[] dfs(int n, int a, int b, int[][][] memo) {
        if (a + b == n + 1) return new int[]{1, 1};
        if (memo[n][a][b] != 0) {
            int val = memo[n][a][b];
            return new int[]{val >> 16, val & 0xFFFF};
        }

        int minRound = Integer.MAX_VALUE;
        int maxRound = Integer.MIN_VALUE;

        int half = (n + 1) / 2;
        for (int mask = 0; mask < (1 << half); mask++) {
            List<Integer> next = new ArrayList<>();
            for (int i = 1; i <= half; i++) {
                int j = n - i + 1;
                if (i == j) {
                    next.add(i);
                } else {
                    int win = ((mask >> (i - 1)) & 1) == 1 ? j : i);
                    next.add(win);
                }
            }
            Collections.sort(next);
            int na = -1, nb = -1;
            for (int idx = 0; idx < next.size(); idx++) {
                int val = next.get(idx);
                if (val == a) na = idx + 1;
                if (val == b) nb = idx + 1;
            }
            if (na == -1 || nb == -1) continue;
            int[] res = dfs(next.size(), Math.min(na, nb), Math.max(na, nb), memo);
            minRound = Math.min(minRound, res[0] + 1);
            maxRound = Math.max(maxRound, res[1] + 1);
        }

        memo[n][a][b] = (minRound << 16) | maxRound;
        return new int[]{minRound, maxRound};
    }
}
